import{_ as i,o as r,c as t,ag as e}from"./chunks/framework.BuUvxvtQ.js";const p=JSON.parse('{"title":"Безопасность аккаунта Instagram","description":"","frontmatter":{},"headers":[],"relativePath":"instagram-security.md","filePath":"instagram-security.md"}'),l={name:"instagram-security.md"};function s(n,a,o,d,c,h){return r(),t("div",null,[...a[0]||(a[0]=[e('<h1 id="безопасность-аккаунта-instagram" tabindex="-1">Безопасность аккаунта Instagram <a class="header-anchor" href="#безопасность-аккаунта-instagram" aria-label="Permalink to &quot;Безопасность аккаунта Instagram&quot;">​</a></h1><p>Instagram часто содержит личные фотографии, переписку, историю публикаций и подписки. Для многих пользователей это также часть публичного образа, поэтому защита аккаунта влияет не только на конфиденциальность, но и на репутацию.</p><h2 id="базовые-меры-защиты" tabindex="-1">Базовые меры защиты <a class="header-anchor" href="#базовые-меры-защиты" aria-label="Permalink to &quot;Базовые меры защиты&quot;">​</a></h2><div class="card-grid"><div class="platform-card"><h3>Уникальный пароль</h3><p>Пароль Instagram не должен совпадать с паролем почты, банковских сервисов или других социальных сетей.</p></div><div class="platform-card"><h3>Двухфакторная аутентификация</h3><p>Включите дополнительное подтверждение входа и заранее сохраните резервные варианты доступа.</p></div><div class="platform-card"><h3>Проверка входов</h3><p>Отслеживайте список устройств, браузеров и мест входа, чтобы вовремя заметить подозрительную активность.</p></div></div><h2 id="настроики-приватности-и-публикации" tabindex="-1">Настройки приватности и публикаций <a class="header-anchor" href="#настроики-приватности-и-публикации" aria-label="Permalink to &quot;Настройки приватности и публикаций&quot;">​</a></h2><ul><li>решите, нужен ли вам открытый профиль или закрытый доступ только для подписчиков;</li><li>проверьте, кто может отправлять сообщения, отмечать вас и отвечать на истории;</li><li>ограничьте публикацию геолокации в реальном времени;</li><li>периодически пересматривайте старые публикации, на которых могут быть лишние персональные данные.</li></ul><h2 id="что-делать-после-подозрительного-входа" tabindex="-1">Что делать после подозрительного входа <a class="header-anchor" href="#что-делать-после-подозрительного-входа" aria-label="Permalink to &quot;Что делать после подозрительного входа&quot;">​</a></h2><ol><li>Измените пароль на надежный и уникальный.</li><li>Завершите все посторонние сеансы.</li><li>Проверьте почту, номер телефона и резервные способы восстановления.</li><li>Пересмотрите подключенные приложения и сайты.</li><li>Сообщите знакомым, если от вашего имени рассылались подозрительные сообщения.</li></ol><div class="screenshot-placeholder"> Здесь будет размещен актуальный скриншот настроек безопасности Instagram: двухфакторная аутентификация, активность входов, параметры сообщений и приватности. </div>',9)])])}const _=i(l,[["render",s]]);export{p as __pageData,_ as default};
